function MemoizedComponent() {
  const [array, setArray] = useState([]);
  useEffect(() => {
    // Create a new array reference on every render
    setArray([...array, { id: Math.floor(Math.random() * 100), name: `Person ${Math.floor(Math.random() * 100)}` }]);
  }, []);

  return <>Array: {JSON.stringify(array)}</>;
}

