# Solution
import random
from functools import lru_cache

class MemoizedComponent:
  def __init__(self):
    self.array = []

  def handle_update(self):
    # Memoize the array reference
    self.array = lru_cache(maxsize=None)(lambda array: [item for item in array] + [{ 'id': random.randint(1, 100), 'name': f'Person {random.randint(1, 100)}' }])(self.array)

  def render(self):
    return f'Array: {self.array}'
